<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function srError(m){$('.isi_warning_delete').text(m||'Selection Result gagal diproses.');$('.error_data_delete').fadeIn();}
function srFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),selection_stage:$('#filter_selection_stage').val(),selection_status:$('#filter_selection_status').val(),decision_result:$('#filter_decision_result').val(),vacancy_id:$('#filter_vacancy_id').val(),keyword:$('#filter_keyword').val()};}
function srSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function ajaxSel(s,act,ph,parent,extra){$(s).select2({width:'100%',allowClear:true,placeholder:ph,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/selection_result/selection_result_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){var d={term:q.term||''};if(extra)$.extend(d,extra());return d;},processResults:function(d){return{results:d.results||[]};}}});}
function nextNo(){ $.post('<?=base_admin();?>modul/selection_result/selection_result_action.php?act=next_no',{year:($('#selection_date').val()||'<?=date('Y');?>').substr(0,4)},function(r){if(r.status==='good')$('#selection_no').val(r.selection_no);},'json');}
function resetSr(t){$('#form_sr')[0].reset();$('#sr_id').val('');$('#selection_date').val('<?=date('Y-m-d');?>');$('#selection_stage').val('FINAL').trigger('change');$('#selection_status').val('DRAFT').trigger('change');$('#decision_result').val('PENDING').trigger('change');$('#recommendation').val('PENDING').trigger('change');$('#next_action').val('NONE').trigger('change');$('#currency').val('IDR').trigger('change');$('#applicant_id,#vacancy_id,#final_interview_id,#proposed_position_id,#proposed_job_title_id,#approved_by_employee_id').val(null).trigger('change');$('#screening_score,#interview_score,#assessment_score,#overall_score,#proposed_salary').val(0);$('#modal_sr .modal-title').text(t||'Create Selection Result');nextNo();}
function calcScore(){var vals=[];['#screening_score','#interview_score','#assessment_score'].forEach(function(s){var v=parseFloat($(s).val())||0;if(v>0)vals.push(v);});if(vals.length&&!$('#overall_score').is(':focus'))$('#overall_score').val((vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(2));}
$(function(){if($.fn.datepicker){$('.sr-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_selection_stage,#filter_selection_status,#filter_decision_result,#selection_stage,#selection_status,#decision_result,#recommendation,#next_action,#currency').select2({width:'100%',allowClear:true});ajaxSel('#filter_vacancy_id','vacancy_search','Semua Vacancy');ajaxSel('#applicant_id','applicant_search','Pilih Applicant',$('#modal_sr'));ajaxSel('#vacancy_id','vacancy_search','Pilih Vacancy',$('#modal_sr'));ajaxSel('#final_interview_id','interview_search','Pilih Interview',$('#modal_sr'),function(){return{applicant_id:$('#applicant_id').val()||0};});ajaxSel('#proposed_position_id','position_search','Pilih Position',$('#modal_sr'));ajaxSel('#proposed_job_title_id','job_title_search','Pilih Job Title',$('#modal_sr'));ajaxSel('#approved_by_employee_id','employee_search','Pilih Approver',$('#modal_sr'));}
var dt=$('#dtb_selection_result').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[6,9],className:'text-right'},{width:'42px',targets:0},{width:'150px',targets:1}],ajax:{url:'<?=base_admin();?>modul/selection_result/selection_result_data.php',type:'post',data:function(d){$.extend(d,srFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_selected').text(k.selected||0);$('#kpi_rejected').text(k.rejected||0);$('#kpi_hold').text(k.hold||0);$('#kpi_approved').text(k.approved||0);$('#kpi_avg_score').text(k.avg_score||0);return j.data||[];},error:function(xhr){console.log(xhr.responseText);srError('Data Selection Result gagal dimuat.');}}});
$('#btn_open_sr').click(function(){resetSr('Create Selection Result');$('#modal_sr').modal({backdrop:'static',keyboard:false});});$('#btn_next_sr,#selection_date').on('click change',nextNo);$('#screening_score,#interview_score,#assessment_score').on('keyup change',calcScore);$('#btn_filter_sr').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_sr').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_selection_stage,#filter_selection_status,#filter_decision_result,#filter_vacancy_id').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_sr').click(function(){window.location='<?=base_admin();?>modul/selection_result/selection_result_action.php?act=export&'+$.param(srFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$('#applicant_id').on('select2:select',function(e){$.post('<?=base_admin();?>modul/selection_result/selection_result_action.php?act=applicant_info',{id:e.params.data.id},function(r){if(r.status!=='good')return;var d=r.data||{};srSet('#vacancy_id',d.vacancy_id,d.vacancy_text);srSet('#final_interview_id',d.final_interview_id,d.interview_text);srSet('#proposed_position_id',d.proposed_position_id,d.position_text);srSet('#proposed_job_title_id',d.proposed_job_title_id,d.job_title_text);$('#screening_score').val(d.screening_score||0);$('#interview_score').val(d.interview_score||0);$('#overall_score').val(d.overall_score||0);$('#proposed_grade').val(d.proposed_grade||'');$('#proposed_salary').val(d.proposed_salary||0);$('#currency').val(d.currency||'IDR').trigger('change');$('#proposed_join_date').val(d.proposed_join_date||'');},'json');});
$('#form_sr').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/selection_result/selection_result_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Selection');if(r.status==='good'){$('#modal_sr').modal('hide');dt.draw(false);Swal.fire('Saved','Selection Result berhasil disimpan.','success');}else srError(r.error_message);},'json').fail(function(xhr){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Selection');srError(xhr.responseText);});});
$(document).on('click','.btn-sr-detail',function(){$.post('<?=base_admin();?>modul/selection_result/selection_result_action.php?act=detail',{id:$(this).data('id')},function(h){$('#sr_detail_body').html(h);$('#modal_sr_detail').modal('show');});});
$(document).on('click','.btn-sr-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/selection_result/selection_result_action.php?act=get',{id:id},function(r){if(r.status!=='good'){srError(r.error_message);return;}resetSr('Edit Selection Result');var h=r.data||{};Object.keys(h).forEach(function(k){var el=$('#'+k);if(el.length&&!['applicant_id','vacancy_id','final_interview_id','proposed_position_id','proposed_job_title_id','approved_by_employee_id'].includes(k))el.val(h[k]);});$('#sr_id').val(h.id);srSet('#applicant_id',h.applicant_id,h.applicant_text);srSet('#vacancy_id',h.vacancy_id,h.vacancy_text);srSet('#final_interview_id',h.final_interview_id,h.interview_text);srSet('#proposed_position_id',h.proposed_position_id,h.position_text);srSet('#proposed_job_title_id',h.proposed_job_title_id,h.job_title_text);srSet('#approved_by_employee_id',h.approved_by_employee_id,h.approved_by_text);$('#selection_stage,#selection_status,#decision_result,#recommendation,#next_action,#currency').trigger('change');$('#modal_sr').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-sr-status',function(){var id=$(this).data('id'),status=$(this).data('status');$.post('<?=base_admin();?>modul/selection_result/selection_result_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Updated','Status berhasil diubah.','success');}else srError(r.error_message);},'json');});
$(document).on('click','.btn-sr-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/selection_result/selection_result_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else srError(r.error_message);},'json');});});
});
</script>
